schemaSnapshot.query:
query FulfillmentConstraintRuleSchemaSnapshot {
  __schema {
    queryType {
      fields {
        name
      }
    }
    mutationType {
      fields {
        name
        args {
          name
        }
      }
    }
  }
}

functionCatalog.query:
query FulfillmentConstraintRuleFunctionCatalog {
  fulfillmentConstraintFunctions: shopifyFunctions(apiType: "FULFILLMENT_CONSTRAINT_RULE", first: 10) {
    nodes {
      id
      title
      handle
      apiType
    }
  }
}

errorShape.query:
mutation FulfillmentConstraintRuleErrorShape {
  missing: fulfillmentConstraintRuleCreate(deliveryMethodTypes: [SHIPPING]) {
    fulfillmentConstraintRule {
      id
    }
    userErrors {
      code
      field
      message
    }
  }
  multiple: fulfillmentConstraintRuleCreate(
    functionId: "gid://shopify/ShopifyFunction/999999999999"
    functionHandle: "definitely-missing-fulfillment-constraint"
    deliveryMethodTypes: [SHIPPING]
  ) {
    fulfillmentConstraintRule {
      id
    }
    userErrors {
      code
      field
      message
    }
  }
  emptyDelivery: fulfillmentConstraintRuleCreate(
    functionId: "gid://shopify/ShopifyFunction/999999999999"
    deliveryMethodTypes: []
  ) {
    fulfillmentConstraintRule {
      id
    }
    userErrors {
      code
      field
      message
    }
  }
  deleteUnknown: fulfillmentConstraintRuleDelete(id: "gid://shopify/FulfillmentConstraintRule/999999999999") {
    success
    userErrors {
      code
      field
      message
    }
  }
  updateUnknown: fulfillmentConstraintRuleUpdate(
    id: "gid://shopify/FulfillmentConstraintRule/999999999999"
    deliveryMethodTypes: [SHIPPING]
  ) {
    fulfillmentConstraintRule {
      id
    }
    userErrors {
      code
      field
      message
    }
  }
}

readEmpty.query:
query FulfillmentConstraintRulesEmptyRead {
  fulfillmentConstraintRules {
    id
    deliveryMethodTypes
    function {
